import{_ as t,o as a,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"70. Leave To Engage In Voluntary Emergency Management","description":"","frontmatter":{"title":"70. Leave To Engage In Voluntary Emergency Management","eba":"Doctors in Training 2022-2026","topics":["leave","preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/leave/70-leave-to-engage-in-voluntary-emergency-management.md","filePath":"ebas/doctors-in-training/leave/70-leave-to-engage-in-voluntary-emergency-management.md"}'),r={name:"ebas/doctors-in-training/leave/70-leave-to-engage-in-voluntary-emergency-management.md"};function i(s,e,c,m,l,g){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_70-leave-to-engage-in-voluntary-emergency-management" tabindex="-1">70. Leave To Engage In Voluntary Emergency Management <a class="header-anchor" href="#_70-leave-to-engage-in-voluntary-emergency-management" aria-label="Permalink to &quot;70. Leave To Engage In Voluntary Emergency Management&quot;">​</a></h1><p>Activities</p><p><strong>70.1</strong> A Doctor who engages in a voluntary emergency management activity with a recognised emergency management body that requires the attendance of the Doctor at a time when the Doctor would otherwise be required to be at work is entitled to leave for:</p><p><strong>(a)</strong> time when the Doctor engages in the activity;</p><p><strong>(b)</strong> reasonable travelling time associated with the activity; and</p><p><strong>(c)</strong> reasonable rest time immediately following the activity.</p><p><strong>70.2</strong> The Doctor must advise the Employer as soon as reasonably practicable if the Doctor is requested to attend a voluntary emergency management activity and must advise the Employer of the expected or likely duration of the Doctor’s attendance. The Doctor must provide a certificate of attendance or other evidence of attendance as reasonably requested by the Employer.</p><p><strong>70.3</strong> Recognised emergency management bodies include but are not limited to, the Country Fire Authority, Red Cross, State Emergency Service and St John Ambulance.</p><p><strong>70.4</strong> A Doctor who is required to attain qualifications or to requalify to perform activities in an emergency management body must be granted leave with pay for the period of time required to fulfil the requirements of the training course pertaining to those qualifications, provided that such training can be undertaken without unduly affecting the operations of the Employer.</p><p><strong>70.5</strong> The leave under this clause will be paid up to two weeks, save that approval of paid leave is subject to the operational requirements of the Employer resulting from any emergency.</p><p><strong>70.6</strong> Nothing in this clause limits the ability of a Doctor to be absent from employment for engaging in eligible community service activity in accordance with Division 8 of the Act.</p><p>Note: Under the Act, an employee who engages in an eligible community service activity is entitled to be absent from employment without pay (or in some circumstances, with pay). The relevant period consists of time engaged in the community service activity, reasonable travel</p><p>time and reasonable rest time. Eligible community service activity means jury service, a voluntary emergency service management activity (such as voluntary work relating to an emergency or natural disaster when performed for a recognised emergency management body - as defined), or an activity prescribed from time to time. There are particular notice requirements so that the employer is advised of the forthcoming absence and how long it is expected to last. For jury service, there are special rules about pay rates, there is a limit of 10 days&#39; paid leave and jury service does not apply to casual employees. Note also that any more generous State or Territory community service leave entitlements may nevertheless apply.</p>',13)])])}const p=t(r,[["render",i]]);export{d as __pageData,p as default};
